AyB,mBAAO,CAAC,uDAAkE;AACnG;AACA,qBAAqB,mBAAO,CAAC,uaAAqX;AAClZ;AACA,uBAAuB,mBAAO,CAAC,4PAAgP;AAC/Q;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED","file":"120.js","sourcesContent":["<template>\r\n    <el-dialog :title=\"titleDialog\" width=\"40%\"  :visible=\"showDialog\"  @open=\"create\"  :close-on-click-modal=\"false\" :close-on-press-escape=\"false\" append-to-body :show-close=\"false\">\r\n\r\n        <div class=\"form-body\">\r\n            <div class=\"row\" >\r\n                <div class=\"col-lg-12 col-md-12 table-responsive\">\r\n                    <div class=\"col-lg-5 col-md-5 col-sm-12 pb-2\">\r\n                        <el-input placeholder=\"Buscar serie ...\"\r\n                            v-model=\"search\"\r\n                            style=\"width: 100%;\"\r\n                            prefix-icon=\"el-icon-search\"\r\n                            @input=\"filter\">\r\n                         <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                    </div>\r\n                    <table width=\"100%\" class=\"table\">\r\n                        <thead>\r\n                            <tr width=\"100%\">\r\n                                <th class=\"text-center\">Seleccionar</th>\r\n                                <th >Cod. Lote</th>\r\n                                <th>Serie</th>\r\n                                <th>Fecha</th>\r\n                            </tr>\r\n                        </thead>\r\n                        <tbody>\r\n                            <tr v-for=\"(row, index) in lots_\" :key=\"index\" width=\"100%\">\r\n                                <!-- <td>{{index}}</td> -->\r\n                                <td class=\"text-center\">\r\n                                    <el-checkbox v-model=\"row.has_sale\"></el-checkbox>\r\n                                </td>\r\n                                <td>\r\n                                    {{row.lot_code}}\r\n                                </td>\r\n                                <td>\r\n                                    {{row.series}}\r\n                                </td>\r\n                                <td>\r\n                                    {{row.date}}\r\n                                </td>\r\n                                <br>\r\n                            </tr>\r\n                        </tbody>\r\n                    </table>\r\n\r\n\r\n                </div>\r\n\r\n            </div>\r\n        </div>\r\n\r\n       <div class=\"form-actions text-end pt-2 pb-2\">\r\n            <el-button @click.prevent=\"close()\">Cerrar</el-button>\r\n            <!-- <el-button type=\"primary\" @click=\"submit\" >Guardar</el-button> -->\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n    export default {\r\n        props: ['showDialog', 'lots', 'stock','recordId'],\r\n        data() {\r\n            return {\r\n                titleDialog: 'Series',\r\n                loading: false,\r\n                errors: {},\r\n                form: {},\r\n                search: '',\r\n                lots_: []\r\n            }\r\n        },\r\n        async created() {\r\n\r\n        },\r\n        watch:{\r\n            lots(val)\r\n            {\r\n                this.lots_ = val\r\n            }\r\n        },\r\n        methods: {\r\n            filter()\r\n            {\r\n\r\n                if(this.search)\r\n                {\r\n                    // this.lots_ = this.lots.filter( x => x.series.toUpperCase().includes(this.search.toUpperCase()))\r\n                    this.lots_ = _.filter(this.lots, x => x.series.toUpperCase().includes(this.search.toUpperCase()))\r\n                }\r\n                else{\r\n                    this.lots_ = this.lots\r\n                }\r\n            },\r\n            create(){\r\n\r\n            },\r\n            async submit(){\r\n\r\n                // let val_lots = await this.validateLots()\r\n                // if(!val_lots.success)\r\n                //     return this.$toast.error(val_lots.message);\r\n\r\n                // await this.$emit('addRowLot', this.lots);\r\n                // await this.$emit('update:showDialog', false)\r\n\r\n            },\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n                this.$emit('addRowSelectLot', this.lots_);\r\n            },\r\n            async clickCancelSubmit() {\r\n\r\n                // this.$emit('addRowLot', []);\r\n                // await this.$emit('update:showDialog', false)\r\n\r\n            },\r\n        }\r\n    }\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/documents/partials/lots.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        append-to-body\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-8\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\">Producto</label>\r\n                            <el-input\r\n                                v-model=\"form.item_description\"\r\n                                :readonly=\"true\"\r\n                            ></el-input>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Stock en el sistema</label\r\n                            >\r\n                            <el-input\r\n                                v-model=\"form.quantity\"\r\n                                :readonly=\"true\"\r\n                            ></el-input>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\">Almacén</label>\r\n                            <el-input\r\n                                v-model=\"form.warehouse_description\"\r\n                                :readonly=\"true\"\r\n                            ></el-input>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\">Stock real</label>\r\n                            <el-input v-model=\"form.quantity_real\"></el-input>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div\r\n                        class=\"col-md-4 mt-4\"\r\n                        v-if=\"\r\n                            form.item_id &&\r\n                                form.warehouse_id &&\r\n                                form.series_enabled\r\n                        \"\r\n                    >\r\n                        <!-- <el-button type=\"primary\" native-type=\"submit\" icon=\"el-icon-check\">Elegir serie</el-button> -->\r\n                        <a\r\n                            href=\"#\"\r\n                            class=\"text-center font-weight-bold text-info\"\r\n                            @click.prevent=\"clickLotcodeOutput\"\r\n                            >[&#10004; Seleccionar series]</a\r\n                        >\r\n                    </div>\r\n\r\n                    <div\r\n                        class=\"col-md-4 mt-4\"\r\n                        v-if=\"\r\n                            form.item_id &&\r\n                                form.warehouse_id &&\r\n                                form.lots_enabled\r\n                        \"\r\n                    >\r\n                        <a\r\n                            href=\"#\"\r\n                            class=\"text-center font-weight-bold text-info\"\r\n                            @click.prevent=\"clickSelectLotsGroup\"\r\n                            >[&#10004; Seleccionar lotes]</a\r\n                        >\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-end mt-4\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Aceptar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n        <output-lots-form\r\n            :showDialog.sync=\"showDialogLotsOutput\"\r\n            :itemId=\"form.item_id\"\r\n            :lots-all=\"lotsAll\"\r\n            :lots=\"form.lots\"\r\n            :quantity=\"form.quantity_real\"\r\n            :warehouseId=\"form.warehouse_id\"\r\n            @addRowOutputLot=\"addRowOutputLot\"\r\n        >\r\n        </output-lots-form>\r\n\r\n        <output-lots-group-form\r\n            :showDialog.sync=\"showDialogLotsGroup\"\r\n            :itemId=\"form.item_id\"\r\n            :lots-group-all=\"lotsGroupAll\"\r\n            :lots_group=\"form.lots_group\"\r\n            :quantity=\"form.quantity_real\"\r\n            @addRowLotGroup=\"addRowLotGroup\"\r\n            :compromise-all-quantity=\"true\"\r\n        >\r\n        </output-lots-group-form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport OutputLotsForm from \"../../../../js/views/documents/partials/lots.vue\";\r\nimport OutputLotsGroupForm from \"../../../../js/views/documents/partials/lots.vue\";\r\n//import OutputLotsForm from './partials/lots.vue'\r\n\r\nexport default {\r\n    components: { OutputLotsForm, OutputLotsGroupForm },\r\n    props: [\"showDialog\", \"recordId\"],\r\n    data() {\r\n        return {\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            showDialogLotsOutput: false,\r\n            showDialogLotsGroup: false,\r\n            resource: \"inventory\",\r\n            errors: {},\r\n            form: {},\r\n            warehouses: [],\r\n            lotsAll: [],\r\n            lotsGroupAll: []\r\n        };\r\n    },\r\n    async created() {\r\n        this.initForm();\r\n        // await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n        //     this.warehouses = response.data.warehouses;\r\n        // });\r\n    },\r\n    methods: {\r\n        addRowOutputLot(lots) {\r\n            this.form.lots = lots;\r\n        },\r\n        addRowLotGroup(id) {\r\n            this.form.selected_lots_group = id;\r\n        },\r\n        clickLotcodeOutput() {\r\n            this.showDialogLotsOutput = true;\r\n        },\r\n        clickSelectLotsGroup() {\r\n            this.showDialogLotsGroup = true;\r\n        },\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                item_id: null,\r\n                item_description: null,\r\n                warehouse_id: null,\r\n                warehouse_description: null,\r\n                quantity: null,\r\n                quantity_real: null,\r\n                lots_enabled: false,\r\n                series_enabled: false,\r\n                lots: []\r\n            };\r\n        },\r\n        async create() {\r\n            this.titleDialog = \"Ajuste de stock 3\";\r\n            await this.$http\r\n                .get(`/${this.resource}/record/${this.recordId}`)\r\n                .then(response => {\r\n                    let data = response.data.data;\r\n                    this.form = _.clone(data);\r\n                    this.form.lots = [];\r\n                    this.form.lots_group = []; //Object.values(response.data.data.lots)\r\n                    this.lotsAll = data.lots;\r\n                    this.lotsGroupAll = data.lots_group; //Object.values(response.data.data.lots);\r\n                    this.form = Object.assign({}, this.form, {\r\n                        quantity_real: 0\r\n                    });\r\n                });\r\n        },\r\n        async submit() {\r\n            if (this.form.series_enabled) {\r\n                //let select_lots = await _.filter(this.form.lots, {'has_sale': true})\r\n                if (\r\n                    this.form.lots.length !== parseInt(this.form.quantity_real)\r\n                ) {\r\n                    return this.$toast.error(\r\n                        \"La cantidad ingresada es diferente a las series seleccionadas\"\r\n                    );\r\n                }\r\n            }\r\n\r\n            this.loading_submit = true;\r\n            await this.$http\r\n                .post(`/${this.resource}/stock`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                        this.close();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/items/partials/stock.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        @open=\"open\"\r\n        append-to-body\r\n        top=\"7vh\"\r\n        v-loading=\"loading\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\" v-if=\"warehouses\">\r\n                        <table class=\"table\">\r\n                            <thead>\r\n                                <tr>\r\n                                    <th>Ubicación</th>\r\n                                    <th class=\"text-end\">Stock</th>\r\n                                    <th></th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                                <tr v-for=\"(row, idx) in warehouses\" :key=\"idx\">\r\n                                    <th>{{ row.warehouse_description }}</th>\r\n                                    <th class=\"text-end\">\r\n                                        <template v-if=\"item.max_quantity\">\r\n                                            {{\r\n                                                (\r\n                                                    row.stock /\r\n                                                    item.max_quantity\r\n                                                ).toFixed(2)\r\n                                            }}\r\n                                        </template>\r\n                                        <template v-else>\r\n                                            <template\r\n                                                v-if=\"config && config.college\"\r\n                                            >\r\n                                                {{ parseInt(row.stock) }}\r\n                                            </template>\r\n                                            <template v-else>\r\n                                                {{ row.stock }}\r\n                                            </template>\r\n                                        </template>\r\n                                    </th>\r\n                                    <th>\r\n                                        <button\r\n                                            type=\"button\"\r\n                                            class=\"btn waves-effect waves-light btn-sm btn-warning\"\r\n                                            @click.prevent=\"clickStock(row)\"\r\n                                        >\r\n                                            Ajuste\r\n                                            <el-tooltip\r\n                                                class=\"item\"\r\n                                                content=\"Ajuste: stock del sistema no cuadre con el stock real\"\r\n                                                effect=\"dark\"\r\n                                                placement=\"top\"\r\n                                            >\r\n                                                <i\r\n                                                    class=\"fa fa-info-circle\"\r\n                                                ></i>\r\n                                            </el-tooltip>\r\n                                        </button>\r\n                                    </th>\r\n                                </tr>\r\n                                <tr>\r\n                                    <td>\r\n                                        Total\r\n                                    </td>\r\n                                    <td\r\n                                        class=\"text-end\"\r\n                                        template\r\n                                        v-if=\"config && config.college\"\r\n                                    >\r\n                                        {{ parseInt(total) }}\r\n                                    </td>\r\n                                    <td class=\"text-end\" template v-else>\r\n                                        {{ total.toFixed(2) }}\r\n                                    </td>\r\n                                    <td></td>\r\n                                </tr>\r\n                            </tbody>\r\n                        </table>\r\n                        <div v-if=\"hasSerie\">\r\n                            <table class=\"table\">\r\n                                <tbody>\r\n                                    <tr>\r\n                                        <td>\r\n                                            Total de series activas:\r\n                                        </td>\r\n                                        <td class=\"text-end\">\r\n                                            <strong>\r\n                                                {{ series }}\r\n                                            </strong>\r\n                                        </td>\r\n                                    </tr>\r\n                                </tbody>\r\n                            </table>\r\n                        </div>\r\n                        <div v-if=\"unit_type.length > 0\">\r\n                            <h6>Lista de Precios Creados</h6>\r\n                            <table class=\"table\">\r\n                                <thead>\r\n                                    <tr>\r\n                                        <th>Unidad</th>\r\n                                        <th>Description</th>\r\n                                        <th>Cantidad</th>\r\n                                        <th>Precio</th>\r\n                                        <th>Total</th>\